// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract StudentStartupFund {
    enum ProjectStatus {
        Upcoming,
        Funding,
        Ongoing,
        Completed,
        Cancelled
    }

    struct Project {
        uint256 id;
        string title;
        string description;
        string image;
        string teamJson;
        string tokenName;
        string tokenSymbol;
        address tokenAddress;
        uint256 tokenPrice;
        uint256 goal;
        uint256 totalDonated;
        uint256 projectStart;
        uint256 projectEnd;
        uint256 iocStart;
        uint256 iocEnd;
        uint256 trustVotes;
        uint256 withdrawVotes;
        ProjectStatus status;
        bool active;
        uint256 dividendPool;
        uint256 dividendDenominator;
        bool dividendsFinalized;
    }

    struct Comment {
        address user;
        string content;
        uint8 rating;
        uint256 timestamp;
    }

    address public owner;

    Project[] public projects;
    uint256 public projectCount;

    mapping(uint256 => Comment[]) private projectComments;

    mapping(uint256 => mapping(address => uint256)) public donatedByUser;
    mapping(uint256 => mapping(address => uint256)) public claimedDividends;

    mapping(uint256 => mapping(address => bool)) public votedTrust; // votedTrust là mapping để lưu trữ thông tin về việc người dùng đã bỏ phiếu tín nhiệm cho dự án nào.
    mapping(uint256 => mapping(address => bool)) public votedWithdraw; // votedWithdraw là mapping để lưu trữ thông tin về việc người dùng đã bỏ phiếu giải ngân cho dự án nào.

    event ProjectCreated(uint256 indexed projectId, string title);
    event DonationReceived(uint256 indexed projectId, address indexed donor, uint256 amount);
    event CommentAdded(uint256 indexed projectId, address indexed user, uint8 rating, string content);
    event VotedTrust(uint256 indexed projectId, address indexed user);
    event VotedWithdraw(uint256 indexed projectId, address indexed user); // VotedWithdraw là sự kiện được phát ra khi người dùng đã bỏ phiếu giải ngân cho dự án nào.
    event Withdrawn(uint256 indexed projectId, address indexed to, uint256 amount); // Withdrawn là sự kiện được phát ra khi người dùng đã rút tiền từ dự án nào.
    event ProjectDisbursed(
        uint256 indexed projectId,
        address indexed treasury,
        uint256 treasuryAmount,
        uint256 dividendPool
    );
    event DividendClaimed(uint256 indexed projectId, address indexed user, uint256 amount);

    // modifier onlyOwner để kiểm tra nếu msg.sender là owner thì thực hiện hàm.
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner"); // kiểm tra nếu msg.sender là owner thì thực hiện hàm.
        _; // _ là một hàm để thực hiện hàm.
    }

    // modifier validProject để kiểm tra nếu projectId là valid thì thực hiện hàm.
    modifier validProject(uint256 projectId) {
        require(projectId < projects.length, "Invalid project"); // kiểm tra nếu projectId là valid thì thực hiện hàm.
        _; // _ là một hàm để thực hiện hàm.
    }

    // constructor để khởi tạo contract.
    constructor() {
        owner = msg.sender; // owner là địa chỉ của người tạo contract. msg.sender là địa chỉ của người gửi giao dịch.
    }

    // hàm này dùng để kiểm tra trạng thái của dự án. _computeStatus là hàm để kiểm tra trạng thái của dự án.
    function _computeStatus(
        uint256 /* projectStart */, // projectStart là thời gian bắt đầu của dự án.
        uint256 projectEnd, // projectEnd là thời gian kết thúc của dự án.
        uint256 iocStart, // iocStart là thời gian bắt đầu của gọi vốn.
        uint256 iocEnd // iocEnd là thời gian kết thúc của gọi vốn.
    ) internal view returns (ProjectStatus) {
        // kiểm tra nếu projectEnd > 0 và block.timestamp > projectEnd thì trạng thái là Completed. đã kết thúc gọi vốn. 
        if (projectEnd > 0 && block.timestamp > projectEnd) {
            return ProjectStatus.Completed;
        }
        // kiểm tra nếu block.timestamp >= iocStart và block.timestamp <= iocEnd thì trạng thái là Funding. đang gọi vốn.
        if (block.timestamp >= iocStart && block.timestamp <= iocEnd) {
            return ProjectStatus.Funding;
        }
        // kiểm tra nếu block.timestamp > iocEnd và block.timestamp <= projectEnd thì trạng thái là Ongoing. đang tiến hành gọi vốn.
        if (block.timestamp > iocEnd && block.timestamp <= projectEnd) {
            return ProjectStatus.Ongoing;
        }
        // kiểm tra nếu block.timestamp < iocStart thì trạng thái là Upcoming. chưa mở gọi vốn.
        if (block.timestamp < iocStart) {
            return ProjectStatus.Upcoming;
        }
        // nếu không thỏa mãn các điều kiện trên thì trạng thái là Upcoming. chưa mở gọi vốn.
        return ProjectStatus.Upcoming;
    }

    function createProject(
        string memory title,
        string memory description,
        string memory image,
        string memory teamJson,
        string memory tokenName,
        string memory tokenSymbol,
        address tokenAddress,
        uint256 tokenPrice,
        uint256 goal,
        uint256 projectStart,
        uint256 projectEnd,
        uint256 iocStart,
        uint256 iocEnd
    ) external onlyOwner returns (uint256) {
        require(bytes(title).length > 0, "Title required");
        require(goal > 0, "Goal must be > 0");

        // kiểm tra nếu projectStart và projectEnd chưa được set thì set giá trị mặc định là hiện tại và thêm 90 ngày.
        if (projectStart == 0 && projectEnd == 0) { // projectStart == 0 và projectEnd == 0 thì set giá trị mặc định là hiện tại và thêm 90 ngày.
            projectStart = block.timestamp; // set projectStart là hiện tại.
            projectEnd = block.timestamp + 90 days; // set projectEnd là hiện tại + 90 ngày.
        }
        if (iocStart == 0 && iocEnd == 0) { // nếu iocStart và iocEnd chưa được set thì set giá trị mặc định là hiện tại và thêm 30 ngày.
            iocStart = block.timestamp; // set iocStart là hiện tại.
            iocEnd = block.timestamp + 30 days; // set iocEnd là hiện tại + 30 ngày.
        }

        require(iocStart < iocEnd, "IOC start < end"); // kiểm tra nếu iocStart < iocEnd thì throw error.
        require(projectStart <= projectEnd, "Project start <= end"); // kiểm tra nếu projectStart <= projectEnd thì throw error.

        uint256 id = projects.length; // id là số lượng dự án hiện tại.
        ProjectStatus status = _computeStatus(projectStart, projectEnd, iocStart, iocEnd); // status là trạng thái của dự án.

        projects.push(
            Project({
                id: id,
                title: title,
                description: description,
                image: image,
                teamJson: teamJson,
                tokenName: tokenName,
                tokenSymbol: tokenSymbol,
                tokenAddress: tokenAddress,
                tokenPrice: tokenPrice,
                goal: goal,
                totalDonated: 0,
                projectStart: projectStart,
                projectEnd: projectEnd,
                iocStart: iocStart,
                iocEnd: iocEnd,
                trustVotes: 0,
                withdrawVotes: 0,
                status: status,
                active: true,
                dividendPool: 0,
                dividendDenominator: 0,
                dividendsFinalized: false
            })
        );

        projectCount = projects.length; // projectCount là số lượng dự án hiện tại.

        emit ProjectCreated(id, title); // emit là một hàm để phát ra sự kiện. ProjectCreated là sự kiện được phát ra khi tạo dự án. id là id của dự án, title là tiêu đề của dự án.
        return id; // trả về id của dự án.
    }

    function setProjectActive(uint256 projectId, bool active)
        external
        onlyOwner
        validProject(projectId)
    {
        require(!projects[projectId].dividendsFinalized, "Project finalized");
        projects[projectId].active = active;
    }

    function getProjectsCount() external view returns (uint256) {
        return projects.length;
    }

    function donate(uint256 projectId)
        external
        payable
        validProject(projectId)
    {
        require(msg.value > 0, "Amount must be > 0");

        Project storage p = projects[projectId];
        require(p.active, "Project inactive");
        require(
            block.timestamp >= p.iocStart && block.timestamp <= p.iocEnd,
            "Not in IOC time"
        );

        p.totalDonated += msg.value;
        donatedByUser[projectId][msg.sender] += msg.value;

        emit DonationReceived(projectId, msg.sender, msg.value);
    }

    function addComment(
        uint256 projectId,
        string memory content,
        uint8 rating
    )
        external
        validProject(projectId)
    {
        require(bytes(content).length > 0, "Content required");
        require(rating >= 1 && rating <= 5, "Rating 1-5");

        projectComments[projectId].push(
            Comment({
                user: msg.sender,
                content: content,
                rating: rating,
                timestamp: block.timestamp
            })
        );

        emit CommentAdded(projectId, msg.sender, rating, content);
    }

    function getCommentsCount(uint256 projectId)
        external
        view
        validProject(projectId)
        returns (uint256)
    {
        return projectComments[projectId].length;
    }

    function getComment(uint256 projectId, uint256 index)
        external
        view
        validProject(projectId)
        returns (
            address user,
            string memory content,
            uint8 rating,
            uint256 timestamp
        )
    {
        require(index < projectComments[projectId].length, "Invalid index");
        Comment storage c = projectComments[projectId][index];
        return (c.user, c.content, c.rating, c.timestamp);
    }

    function voteTrust(uint256 projectId)
        external
        validProject(projectId)
    {
        require(!votedTrust[projectId][msg.sender], "Already voted");
        votedTrust[projectId][msg.sender] = true;
        projects[projectId].trustVotes += 1;

        emit VotedTrust(projectId, msg.sender);
    }

    function voteWithdraw(uint256 projectId)
        external
        validProject(projectId)
    {
        require(!votedWithdraw[projectId][msg.sender], "Already voted");
        votedWithdraw[projectId][msg.sender] = true;
        projects[projectId].withdrawVotes += 1;

        emit VotedWithdraw(projectId, msg.sender);
    }

    function disburseAndFinalizeDividends(
        uint256 projectId,
        address payable treasury,
        uint256 treasuryAmount
    )
        external
        onlyOwner
        validProject(projectId)
    {
        Project storage p = projects[projectId];
        require(p.active, "Project inactive");
        require(!p.dividendsFinalized, "Dividends finalized");
        require(p.totalDonated >= p.goal, "Goal not reached");
        require(block.timestamp > p.iocEnd, "IOC not ended");
        require(p.withdrawVotes >= 3, "Not enough votes");
        require(treasury != address(0), "Zero address");
        require(treasuryAmount > 0 && treasuryAmount <= p.totalDonated, "Invalid treasury amount");

        uint256 dividendPool = p.totalDonated - treasuryAmount;
        require(address(this).balance >= p.totalDonated, "Insufficient contract balance");

        p.dividendPool = dividendPool;
        p.dividendDenominator = p.totalDonated;
        p.dividendsFinalized = true;
        p.active = false;

        (bool ok, ) = treasury.call{value: treasuryAmount}("");
        require(ok, "Treasury transfer failed");

        emit ProjectDisbursed(projectId, treasury, treasuryAmount, dividendPool);
    }

    function claimDividends(uint256 projectId)
        external
        validProject(projectId)
    {
        Project storage p = projects[projectId];
        require(p.dividendsFinalized, "Dividends not finalized");
        require(p.dividendPool > 0, "No dividends");

        uint256 userDonated = donatedByUser[projectId][msg.sender];
        require(userDonated > 0, "No donations");

        uint256 owed = (userDonated * p.dividendPool) / p.dividendDenominator;
        uint256 alreadyClaimed = claimedDividends[projectId][msg.sender];
        require(owed > alreadyClaimed, "Nothing to claim");

        uint256 claimable = owed - alreadyClaimed;
        claimedDividends[projectId][msg.sender] = owed;

        (bool ok, ) = payable(msg.sender).call{value: claimable}("");
        require(ok, "Dividend transfer failed");

        emit DividendClaimed(projectId, msg.sender, claimable);
    }

    function withdraw(
        uint256 projectId,
        address payable to,
        uint256 amount
    )
        external
        onlyOwner
        validProject(projectId)
    {
        require(to != address(0), "Zero address");
        require(amount <= address(this).balance, "Insufficient balance");
        require(projects[projectId].withdrawVotes >= 3, "Not enough votes");
        require(projects[projectId].totalDonated >= projects[projectId].goal, "Goal not reached");
        require(block.timestamp > projects[projectId].iocEnd, "IOC not ended");
        require(!projects[projectId].dividendsFinalized, "Dividends finalized");

        (bool ok, ) = to.call{value: amount}("");
        require(ok, "Transfer failed");

        emit Withdrawn(projectId, to, amount);
    }
}

